import com.pinterest.ktlint.ruleset.standard.rules.ImportOrderingRule
import com.pinterest.ktlint.ruleset.standard.rules.ImportOrderingRule.Companion.IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Regression test for issue where multiple blank line patterns in ij_kotlin_imports_layout
 * caused extra blank lines to be inserted before the first import in version 0.48.2.
 *
 * The issue was that when the first import matched a pattern that had blank line separators
 * before it in the layout configuration, those blank lines were incorrectly added before
 * the first import.
 *
 * For example, with layout: "*, |, javax.**, java.**, |, kotlinx.**, kotlin.**"
 * And a file with only java.** imports, ktlint would incorrectly add blank lines before
 * the first import because there was a "|" separator before "java.**" in the pattern.
 */
class ImportOrderingRuleRegressionTest {
    private val importOrderingRuleAssertThat = assertThatRule { ImportOrderingRule() }

    @Test
    fun `Regression - Issue with multiple pipe separators generating extra blank lines before first import`() {
        // This is the exact scenario from the reported issue
        val code =
            """
            package test

            import java.nio.file.Files
            import java.nio.file.Paths
            import java.util.Objects

            object TestData {
                fun loadString(dataset: String): String {
                    val path = Paths.get(Objects.requireNonNull(TestData::class.java.getResource(dataset)).toURI())
                    return String(Files.readAllBytes(path))
                }
            }
            """.trimIndent()

        // With the fix, this should pass without any lint violations
        // Before the fix, it would fail because ktlint would want to add extra blank lines
        // between package and imports
        importOrderingRuleAssertThat(code)
            .withEditorConfigOverride(IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY to "*, |, javax.**, java.**, |, kotlinx.**, kotlin.**")
            .hasNoLintViolations()
    }

    @Test
    fun `Regression - Blank line patterns before first matching pattern should not add blank lines before first import`() {
        val code =
            """
            import kotlin.concurrent.Thread
            import kotlin.io.Closeable
            """.trimIndent()

        // The layout has two blank line separators before kotlin.**
        // These should NOT cause blank lines to be added before the first import
        importOrderingRuleAssertThat(code)
            .withEditorConfigOverride(IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY to "|, |, kotlin.**, *")
            .hasNoLintViolations()
    }

    @Test
    fun `Regression - Multiple groups with blank line separators should only add blank lines between groups`() {
        val code =
            """
            import android.app.Activity

            import java.nio.file.Files

            import kotlin.concurrent.Thread
            """.trimIndent()

        // Layout: android.**, |, java.**, |, kotlin.**, *
        // Should add blank lines BETWEEN groups but NOT before the first import
        importOrderingRuleAssertThat(code)
            .withEditorConfigOverride(IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY to "android.**, |, java.**, |, kotlin.**, *")
            .hasNoLintViolations()
    }

    @Test
    fun `Regression - Formatting should be idempotent - running twice should produce same result`() {
        val code =
            """
            import kotlin.concurrent.Thread
            import java.nio.file.Files
            """.trimIndent()
        val formattedCode =
            """
            import java.nio.file.Files

            import kotlin.concurrent.Thread
            """.trimIndent()

        // First format
        importOrderingRuleAssertThat(code)
            .withEditorConfigOverride(IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY to "*, |, java.**, |, kotlin.**")
            .hasLintViolation(1, 1, "Imports must be ordered according to the pattern specified in .editorconfig")
            .isFormattedAs(formattedCode)

        // Second format - should be idempotent (no further changes)
        importOrderingRuleAssertThat(formattedCode)
            .withEditorConfigOverride(IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY to "*, |, java.**, |, kotlin.**")
            .hasNoLintViolations()
    }

    @Test
    fun `Regression - All imports matching first pattern after blank separators should not add extra blank lines`() {
        val code =
            """
            import com.example.Foo
            import com.example.Bar
            """.trimIndent()

        // Layout starts with blank line separators, but all imports match the wildcard pattern
        // Should NOT add blank lines before first import
        importOrderingRuleAssertThat(code)
            .withEditorConfigOverride(IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY to "*, |, java.**, |, kotlin.**")
            .hasNoLintViolations()
    }
}
"}

